def count_vowels(text):
    vowels = "aeiou"
    count = 0
    for char in text:
        if char.lower() in vowels:
            count += 1
    return count

def clamp(value, low, high):
    """Restricts value to the inclusive range [low, high]."""
    if value < low:
        return low
    elif value > high:
        return high
    else:
        return value

def unique_preserving_order(items):
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
